INSERT INTO `recipes` (`id`, `title`, `description`, `ingredients`, `instructions`, `nutrition_info`, `notes`, `average_rating`, `rating_count`, `prep_time`, `cook_time`, `yields`, `image_url`, `author_id`) VALUES
(26, 'Fiery Cajun-Style Boiled Peanuts', 'Recipe Description: A beloved Southern delicacy gets a fiery Louisiana makeover! These Cajun-style boiled peanuts are simmered to tender perfection in a spicy, salty, and profoundly flavourful brine. They are addictively delicious and the ultimate snack for sharing with friends, watching a game, or just enjoying on your incredible back porch overlooking the hills.', '[\"2 pounds raw or green peanuts, in shell, rinsed thoroughly\",\"1 gallon (16 cups) water, or enough to cover\",\"\\u00bd cup coarse sea salt or kosher salt\",\"\\u00bc cup store-bought Cajun or Creole seasoning (like Tony Chachere\'s or Slap Ya Mama)\",\"2 tablespoons cayenne pepper (use less for milder heat, more if you\'re feeling devilish)\",\"1 tablespoon smoked paprika\",\"1 whole head of garlic, sliced in half horizontally\",\"1 large yellow onion, peeled and quartered\",\"2 jalape\\u00f1os, sliced in half lengthwise (optional, for an extra kick)\"]', '[\"Instant Pot Method (Recommended):\",\"Rinse: Give the raw peanuts a very thorough rinse under cold water to remove any dirt or debris.\",\"Combine: Place the rinsed peanuts, salt, Cajun seasoning, cayenne pepper, smoked paprika, halved garlic head, quartered onion, and jalape\\u00f1os (if using) into the inner pot of your Instant Pot.\",\"Add Water: Pour in the water, ensuring the peanuts are fully submerged but do not exceed the max fill line of your Instant Pot. Give it all a good stir.\",\"Pressure Cook: Secure the lid, set the steam release valve to \\\"Sealing,\\\" and pressure cook on High Pressure for 90 minutes (1 hour and 30 minutes).\",\"Natural Release: Once the cooking cycle is complete, allow the pressure to release naturally for at least 15 minutes before performing a quick release for any remaining pressure.\",\"Soak & Serve: For the best flavour, let the peanuts soak in the hot, spicy brine for at least 30 minutes after cooking. The longer they sit, the more flavour they\'ll absorb. Serve warm.\",\"Traditional Stovetop Method:\",\"Rinse: Thoroughly rinse the raw peanuts under cold water.\",\"Combine: In a large stockpot or Dutch oven, combine all ingredients. Stir well to dissolve the salt.\",\"Boil & Simmer: Bring the pot to a rolling boil over high heat, then reduce the heat to maintain a steady, gentle simmer.\",\"Cook: Cover the pot and let the peanuts simmer for 4 to 8 hours. The exact time will depend on the maturity and freshness of the peanuts. Check them occasionally, adding more hot water as needed to keep them fully submerged.\",\"Test for Doneness: Start testing the peanuts after about 4 hours. A perfectly cooked boiled peanut should be soft, not crunchy, and the shell should be slightly pliable. They should have the texture of a cooked bean.\",\"Soak & Serve: Once they reach your desired tenderness, turn off the heat and let them soak in the brine for at least 30 minutes before serving.\"]', '{\"Calories\":\"321\",\"Fat\":\"28g (78% of Calories, 36% DV)\",\"Saturated Fat\":\"4g (20% DV)\",\"Cholesterol\":\"0mg (0% DV)\",\"Sodium\":\"2350mg (102% DV)\",\"Carbohydrates\":\"9g (11% of Calories, 3% DV)\",\"Dietary Fiber\":\"5g (18% DV)\",\"Total Sugars\":\"2g\",\"Protein\":\"15g (19% of Calories, 30% DV)\",\"Vitamin A\":\"1% DV\",\"Vitamin C\":\"1% DV\",\"Vitamin D\":\"0% DV\",\"Vitamin E\":\"17% DV\",\"Vitamin K\":\"0% DV\",\"Thiamin (B1)\":\"11% DV\",\"Riboflavin (B2)\":\"4% DV\",\"Niacin (B3)\":\"34% DV\",\"Vitamin B6\":\"9% DV\",\"Folate\":\"30% DV\",\"Vitamin B12\":\"0% DV\",\"Calcium\":\"5% DV\",\"Copper\":\"38% DV\",\"Iron\":\"8% DV\",\"Magnesium\":\"25% DV\",\"Phosphorus\":\"29% DV\",\"Potassium\":\"8% DV\",\"Selenium\":\"10% DV\",\"Zinc\":\"18% DV\"}', 'Peanut Choice is Crucial: It\'s absolutely essential to use raw or, if you can find them, green peanuts. Green peanuts are freshly harvested and have a higher moisture content, so they\'ll cook faster. Do not use roasted peanuts; they simply won\'t soften.\r\nSalt Warning: Do not be alarmed by the amount of salt! It is a brine, after all. The peanuts absorb only a fraction of the sodium, but it\'s necessary to properly flavour them and create that classic taste. The nutritional information reflects a high estimate of sodium absorption; the actual amount may be lower.\r\nSpice It Your Way: This recipe has a proper Cajun kick. Feel free to adjust the cayenne pepper to your personal heat tolerance. You could even toss in a dried chile de árbol or two for a different kind of heat.\r\nStorage: Leftover boiled peanuts should be stored in the refrigerator in an airtight container with some of their brine to keep them from drying out. They\'ll last for up to a week.\r\n\r\nAssumptions:\r\n\r\nThis is a naturally whole-food, plant-based, and oil-free recipe. The nutritional analysis is based on raw peanuts and assumes a moderate absorption of the salt and spices from the brine into the final product. Daily values are based on a 2,000-calorie diet.', 0.00, 0, 10, 1, '10 servings', 'uploads/recipes/68e5743c4782d-firey-cajun-boiled-peanuts.png', 2),
(27, 'Crispy Air Fryer Falafel (with Canned Chickpeas)', 'Achieve falafel perfection without the fuss or the deep fryer! These golden-brown and delightfully crispy falafel balls are packed with fresh herbs and classic spices. By using canned chickpeas and your air fryer, you get all the authentic, herbaceous, and flavourful results in a fraction of the time, making it the perfect healthy addition to salads, bowls, or stuffed into a warm pita.', '[\"2 (15-ounce) cans of chickpeas, rinsed, drained, and patted very dry\",\"1 cup fresh flat-leaf parsley, packed\",\"1 cup fresh cilantro, packed\",\"\\u00bd a medium yellow onion, roughly chopped\",\"3 cloves garlic, peeled\",\"\\u00bc cup chickpea flour (also called gram or besan flour)\",\"1 tablespoon fresh lemon juice\",\"1 teaspoon baking powder\",\"1 teaspoon ground cumin\",\"1 teaspoon ground coriander\",\"\\u00bd teaspoon salt\",\"\\u00bc teaspoon black pepper\",\"Pinch of cayenne pepper (optional)\",\"Avocado oil spray or other high-heat cooking spray\"]', '[\"Dry the Chickpeas: This is the most crucial step! After rinsing and draining the chickpeas, spread them on a clean kitchen towel or paper towels and gently pat them until they are as dry as you can possibly get them. Let them air dry for a few minutes if you have the time.\",\"Process Aromatics First: In the bowl of a food processor, add the packed parsley, cilantro, chopped onion, and garlic. Pulse several times until the herbs and aromatics are very finely chopped.\",\"Add Chickpeas & Spices: Add the thoroughly dried chickpeas, cumin, coriander, salt, pepper, cayenne (if using), and lemon juice to the food processor. Pulse the mixture in short bursts, scraping down the sides as needed, until the chickpeas are broken down and the mixture resembles a coarse, crumbly meal. Do not over-process into a paste! A bit of texture is what we\'re after.\",\"Bind and Chill: Transfer the mixture to a medium bowl. Sprinkle the chickpea flour and baking powder over the top and mix with a spatula until just combined. Cover the bowl and refrigerate for at least 30 minutes, or up to an hour. This step is vital for the mixture to firm up and become easy to handle.\",\"Shape the Falafel: Preheat your air fryer to 375\\u00b0F (190\\u00b0C). Using a tablespoon or a small cookie scoop, portion out the chilled mixture and roll it between your palms to form small balls, about 1 to 1.5 inches in diameter.\",\"Air Fry to Perfection: Place the falafel balls in the air fryer basket in a single layer, ensuring they aren\'t touching. Lightly spray the tops with a thin coating of oil spray. Air fry for 15-18 minutes, flipping the balls over halfway through the cooking time, until they are golden-brown, crispy, and cooked through. Cook in batches if necessary to avoid overcrowding.\",\"Serve Immediately: Falafel are best enjoyed hot and fresh. Serve them tucked inside a pita, on a salad, or as part of a mezze platter with hummus and tahini sauce.\"]', '{\"Calories\":\"165\",\"Fat\":\"2.5g (14% of Calories, 3% DV)\",\"Saturated Fat\":\"0.3g (2% DV)\",\"Cholesterol\":\"0mg (0% DV)\",\"Sodium\":\"485mg (21% DV)\",\"Carbohydrates\":\"28g (68% of Calories, 10% DV)\",\"Dietary Fiber\":\"7.5g (27% DV)\",\"Total Sugars\":\"4.5g\",\"Protein\":\"8g (19% of Calories, 16% DV)\",\"Vitamin A\":\"15% DV\",\"Vitamin C\":\"12% DV\",\"Vitamin D\":\"0% DV\",\"Vitamin E\":\"3% DV\",\"Vitamin K\":\"65% DV\",\"Thiamin (B1)\":\"11% DV\",\"Riboflavin (B2)\":\"7% DV\",\"Niacin (B3)\":\"5% DV\",\"Vitamin B6\":\"18% DV\",\"Folate\":\"35% DV\",\"Vitamin B12\":\"0% DV\",\"Calcium\":\"7% DV\",\"Copper\":\"32% DV\",\"Iron\":\"18% DV\",\"Magnesium\":\"16% DV\",\"Phosphorus\":\"19% DV\",\"Potassium\":\"12% DV\",\"Selenium\":\"6% DV\",\"Zinc\":\"13% DV\"}', 'The Secret to Crispy: I cannot stress this enough, my dear: the chickpeas must be bone dry. Any excess moisture is the enemy of a crispy falafel and will result in a mushy centre.\r\nA Touch of Oil: While this is an \"oil-free\" recipe in spirit, a very light spritz of cooking spray is our little cheat for achieving that beautiful, golden-brown, crispy exterior that mimics deep frying. The minimal amount of oil helps the Maillard reaction along, which is responsible for browning and flavour development. It\'s a tiny addition for a massive textural payoff.\r\nDon\'t Go Green-Crazy: While we want a lot of herbs, make sure to use just the leaves and tender stems of the parsley and cilantro. Thick, woody stems can make the falafel bitter.\r\nMake-Ahead: You can prepare the falafel mixture and store it in an airtight container in the refrigerator for up to 2 days before shaping and air frying.\r\n\r\nAssumptions:\r\n\r\nThis is a whole-food, plant-based recipe. The nutritional analysis is based on using canned chickpeas and includes the negligible amount of oil from a brief spray. Daily values are based on a 2,000-calorie diet.', 0.00, 0, 15, 15, 'Approx. 24 falafel balls (6 servings of 4 balls)', 'uploads/recipes/68e578b9aea22-crispy-air-fried-falafel.png', 2),
(29, 'Smoky Holiday Seitan Ham', 'A rich, flavorful, and incredibly satisfying plant-based holiday roast made with vital wheat gluten. This roast is loaded with smoky spices and smothered in a decadent agave-mustard glaze, making it the perfect cruelty-free centerpiece for any celebratory meal.', '[\"For the Seitan Roast:\",\"1 1\\/2 cups vital wheat gluten\",\"1\\/4 cup nutritional yeast\",\"2 teaspoons smoked paprika\",\"1 teaspoon onion powder\",\"1 teaspoon garlic powder\",\"1\\/2 teaspoon black pepper, freshly ground\",\"1\\/8 teaspoon ground cloves\",\"1 (15-ounce) can cannellini beans, rinsed and drained\",\"1\\/2 cup vegetable broth, low sodium\",\"1\\/4 cup tamari\",\"2 tablespoons agave nectar\",\"1 tablespoon liquid smoke\",\"1 tablespoon tomato paste\",\"For the Agave-Mustard Glaze:\",\"1\\/4 cup agave nectar\",\"2 tablespoons tamari\",\"1 tablespoon Dijon mustard\",\"1 teaspoon avocado oil (or other neutral oil)\",\"1\\/4 teaspoon garlic powder\"]', '[\"Preheat and Prep: Preheat your oven to 350\\u00b0F (175\\u00b0C). Prepare a double layer of heavy-duty aluminum foil large enough to generously wrap the roast.\",\"Create the Wet Mixture: In a blender or food processor, combine all the ingredients for the Seitan Roast except for the vital wheat gluten and nutritional yeast. Blend until completely smooth. This includes the cannellini beans, vegetable broth, tamari, agave, liquid smoke, tomato paste, and all the spices (paprika, onion\\/garlic powder, pepper, cloves).\",\"Create the Dry Mixture: In a large bowl, whisk together the vital wheat gluten and nutritional yeast until well combined.\",\"Form the Dough: Pour the wet mixture into the bowl with the dry mixture. Stir with a sturdy spatula until a shaggy dough forms.\",\"Knead and Shape: Transfer the dough to a lightly floured surface and knead for 2-3 minutes, just until everything is well combined and the dough feels firm and elastic. Do not over-knead.\",\"Shape and Wrap: Shape the dough into a firm, oblong roast shape, similar to a small ham. Place it on the prepared aluminum foil and wrap it very tightly, twisting the ends to seal it like a large sweet wrapper. This is crucial for the seitan to steam in its own moisture.\",\"First Bake: Place the foil-wrapped roast on a baking sheet and bake for 70 minutes.\",\"Prepare the Glaze: While the roast is baking, whisk all the ingredients for the Agave-Mustard Glaze together in a small bowl until smooth.\",\"Glaze and Final Bake: Carefully remove the roast from the oven. Unwrap the foil (be cautious of hot steam). The roast should be firm to the touch. Place the unwrapped roast back on the baking sheet. Brush it generously with half of the glaze. Return it to the oven and bake for 10 minutes.\",\"Final Glaze: Remove the roast again, brush with the remaining glaze, and bake for a final 10-15 minutes, or until the glaze is bubbling and beautifully caramelized.\",\"Rest: Let the seitan ham rest for at least 15 minutes before slicing. The texture will continue to firm up as it cools.\"]', '{\"Calories\":\"215\",\"Fat\":\"2.2g (9% of Calories)\",\"Saturated Fat\":\"0.3g (2% DV)\",\"Cholesterol\":\"0mg (0% DV)\",\"Sodium\":\"985mg (43% DV)\",\"Carbohydrates\":\"22.3g (61% of Calories)\",\"Dietary Fiber\":\"4g (14% DV)\",\"Total Sugars\":\"12.1g\",\"Protein\":\"27.5g (30% of Calories)\",\"Vitamin A\":\"44mcg (5% DV)\",\"Vitamin C\":\"1mg (1% DV)\",\"Vitamin D\":\"0mcg (0% DV)\",\"Vitamin E\":\"0.3mg (2% DV)\",\"Vitamin K\":\"2mcg (2% DV)\",\"Thiamine (B1)\":\"0.5mg (42% DV)\",\"Riboflavin (B2)\":\"0.4mg (31% DV)\",\"Niacin (B3)\":\"2.5mg (16% DV)\",\"Vitamin B6\":\"0.3mg (18% DV)\",\"Folate\":\"145mcg (36% DV)\",\"Vitamin B12\":\"2.4mcg (100% DV)\",\"Pantothenic Acid (B5)\":\"1.1mg (22% DV)\",\"Calcium\":\"85mg (7% DV)\",\"Copper\":\"0.3mg (33% DV)\",\"Iron\":\"3.8mg (21% DV)\",\"Magnesium\":\"60mg (14% DV)\",\"Phosphorus\":\"295mg (24% DV)\",\"Potassium\":\"350mg (7% DV)\",\"Selenium\":\"25mcg (45% DV)\",\"Zinc\":\"1.5mg (14% DV)\"}', 'The Oil Justification: A touch of oil (1 teaspoon) in the glaze is our secret weapon here. It helps the agave and spices caramelize beautifully, creating that irresistible, glossy, slightly crispy crust that you want on a holiday roast. It emulsifies with the mustard and tamari to create a glaze that clings perfectly. It is a small amount used for a significant culinary and textural payoff, which aligns with our low-oil philosophy.\r\nKnead Gently: The biggest mistake people make with seitan is over-kneading. We\'re not making bread. A few minutes is all you need to bring it together. Over-working it can make the final product tough and rubbery.\r\nPatience is a Virtue: The resting period is not a suggestion, it\'s a requirement! Seitan needs to cool and set. In fact, the texture is often even better the next day. This makes it a perfect dish to prepare a day ahead for a gathering.\r\nServing Suggestions: This will be phenomenal as the centrepiece of a holiday meal, served with roasted vegetables and mashed potatoes. The leftovers make for unbelievable sandwiches.\r\nAssumptions: Nutritional information is estimated based on the listed ingredients and quantities. The brand of nutritional yeast used is assumed to be fortified with Vitamin B12. Sodium content is high due to tamari; using a low-sodium tamari would reduce this significantly.', 0.00, 0, 20, 90, '8 servings', 'uploads/recipes/68e67b5a6437a-holiday-seitan-ham.png', 2),
(30, 'Christopher\'s New Year’s Jambalaya', 'A hearty, flavour-packed, and wonderfully comforting one-pot jambalaya. This plant-based twist on the Louisiana classic combines smoky vegan sausage, the \"holy trinity\" of onion, (carrot, in our case!), and peppers, and is simmered with rice and black-eyed peas for a touch of good luck. It\'s a perfect, satisfying meal to ring in the new year or, frankly, to enjoy on any chilly evening.', '[\"1 tablespoon olive oil\",\"1 (12-14 oz) package vegan sausage (like a smoky andouille style, if you can find it), sliced into 1\\/4-inch rounds\",\"1 large yellow onion, chopped\",\"2 medium carrots, chopped\",\"1 green bell pepper, chopped\",\"1 red bell pepper, chopped\",\"2 cloves garlic, minced\",\"1 teaspoon smoked paprika\",\"1\\/2 teaspoon dried thyme\",\"1\\/4 teaspoon cayenne pepper (optional, for a touch of warmth)\",\"1\\/4 teaspoon celery seed\",\"1 (14.5 ounce) can diced tomatoes, undrained\",\"1 (15 ounce) can black-eyed peas, rinsed and drained\",\"2 cups low-sodium vegetable broth\",\"2 cups long-grain white rice\",\"Salt and black pepper to taste\",\"Optional Garnish: Fresh chopped parsley\"]', '[\"Place a large pot or Dutch oven over medium heat. Add the olive oil and let it shimmer. Add the sliced vegan sausage and cook, stirring occasionally, until it gets nicely browned and a little bit crispy on the edges.\",\"Add the chopped onion, carrots, and bell peppers to the pot with the sausage. Saut\\u00e9 for about 5-7 minutes, stirring often, until the vegetables begin to soften.\",\"Stir in the minced garlic, smoked paprika, thyme, cayenne pepper (if you\'re using it), and celery seed. Cook for 1 minute more, stirring constantly until everything is wonderfully fragrant.\",\"Pour in the undrained diced tomatoes, the rinsed black-eyed peas, the vegetable broth, and the rice. Stir everything together well, scraping up any browned bits from the bottom of the pot.\",\"Bring the mixture to a boil, then immediately reduce the heat to low. Cover the pot tightly and let it simmer for 25 minutes.\",\"After 25 minutes, remove the pot from the heat but keep the lid on. Let it stand, undisturbed, for 5-10 minutes. This allows the rice to finish steaming and absorb the last bit of liquid.\",\"Uncover, fluff the jambalaya with a fork, and season generously with salt and black pepper to your personal taste.\",\"Serve hot, garnished with fresh parsley if you\'re feeling fancy.\"]', '{\"Calories\":\"430\",\"Fat\":\"8.5g (18% of Calories)\",\"Saturated Fat\":\"1.5g (8% DV)\",\"Cholesterol\":\"0mg (0% DV)\",\"Sodium\":\"870mg (38% DV)\",\"Carbohydrates\":\"64g (23% of Calories)\",\"Dietary Fiber\":\"6g (21% DV)\",\"Total Sugars\":\"7g\",\"Protein\":\"24g (21% of Calories)\",\"Vitamin A\":\"110% DV\",\"Vitamin C\":\"130% DV\",\"Vitamin D\":\"0% DV\",\"Vitamin E\":\"10% DV\",\"Vitamin K\":\"12% DV\",\"Thiamin (B1)\":\"30% DV\",\"Riboflavin (B2)\":\"15% DV\",\"Niacin (B3)\":\"25% DV\",\"Pantothenic Acid (B5)\":\"8% DV\",\"Pyridoxine (B6)\":\"20% DV\",\"Biotin (B7)\":\"5% DV\",\"Cobalamin (B12)\":\"0% DV\",\"Calcium\":\"8% DV\",\"Copper\":\"20% DV\",\"Folate\":\"15% DV\",\"Iron\":\"25% DV\",\"Magnesium\":\"15% DV\",\"Phosphorus\":\"20% DV\",\"Potassium\":\"18% DV\",\"Selenium\":\"20% DV\",\"Zinc\":\"12% DV\"}', 'A Note on the Oil: We\'re using just one tablespoon of olive oil for the entire pot, which is quite minimal when spread across 6-8 servings. Its purpose here is purely culinary: it helps to achieve a proper browning (Maillard reaction) on the vegan sausage, which builds a crucial flavour base—a fond—at the bottom of the pot. This rich, browned-on flavour is essential for a truly deep and satisfying jambalaya. You could technically sauté in water or broth, but you would miss out on that foundational savoury note.\r\nRice: Don\'t be tempted to stir the rice while it\'s simmering! This will release starches and make your jambalaya gummy instead of fluffy. Trust the process.\r\nSodium: The sodium content is on the higher side, primarily from the vegan sausage and canned goods. To manage this, be sure to use low-sodium vegetable broth and don\'t salt the dish until the very end, after you\'ve tasted it.\r\nSpice It Up: If you like it hot, feel free to add a pinch more cayenne or even a dash of your favourite vegan hot sauce at the end.', 0.00, 0, 15, 35, '6-8 servings', 'uploads/recipes/68f8b76e0e606-Christopher\'s New Year’s Jambalaya.png', 2),
(31, 'Hearty Instant Pot Black Bean Chili (Oil-Free)', 'This is the ultimate \"set it and forget it\" chili that delivers deep, slow-simmered flavour in a fraction of the time, thanks to the magic of the Instant Pot. Completely oil-free, this recipe uses dried black beans cooked from scratch, resulting in a wonderfully creamy texture and robust taste. It\'s packed with plant-based protein, fibre, and smoky spices—a perfectly healthy, warming, and satisfying meal for any night of the week.', '[\"2 cups dried black beans, soaked overnight (or quick-soaked)\",\"1 large yellow onion, chopped\",\"4 cloves garlic, minced\",\"1 bell pepper (red, orange, or yellow for sweetness), chopped\",\"1 jalape\\u00f1o pepper, finely chopped (optional, for heat)\",\"1 (28-ounce) can crushed tomatoes\",\"4 cups low-sodium vegetable broth\",\"2 tablespoons chili powder\",\"1 tablespoon ground cumin\",\"1 teaspoon smoked paprika\",\"1\\/2 teaspoon dried oregano\",\"1\\/4 teaspoon cayenne pepper (optional, adjust to taste)\",\"Salt and freshly ground black pepper to taste\",\"For Garnish: Fresh cilantro, chopped\"]', '[\"Soak: Ensure your black beans have been soaked overnight (for at least 8 hours). Drain the soaking water and give the beans a thorough rinse.\",\"Saut\\u00e9 Veggies: Select the \\\"Saut\\u00e9\\\" function on your Instant Pot. Once it displays \\\"Hot,\\\" add the chopped onion, bell pepper, and jalape\\u00f1o (if using). Cook for about 5 minutes, stirring occasionally, until the onions soften and become translucent. If they begin to stick, add a splash of the vegetable broth to deglaze the pot. Add the minced garlic and cook for one more minute until fragrant.\",\"Combine Ingredients: Press \\\"Cancel\\\" to turn off the Saut\\u00e9 function. Add the rinsed black beans, crushed tomatoes, the remaining vegetable broth, chili powder, cumin, smoked paprika, oregano, and cayenne pepper to the pot. Stir everything together until well combined.\",\"Pressure Cook: Secure the Instant Pot lid and move the steam release valve to the \\\"Sealing\\\" position. Select the \\\"Manual\\\" or \\\"Pressure Cook\\\" function and set the timer for 30 minutes on high pressure.\",\"Release Pressure: Once the 30-minute cook time is complete, allow the pressure to release naturally for at least 10 minutes. Afterwards, you can carefully switch the valve to \\\"Venting\\\" to release any remaining steam.\",\"Finish & Season: Once the pin drops, carefully open the lid. Give the chili a good stir. The chili will thicken as it cools. For an even thicker consistency, you can use an immersion blender for a few quick pulses or mash some of the beans against the side of the pot with a spoon.\",\"Serve: Season generously with salt and black pepper to your liking. Ladle the hot chili into bowls and garnish with a sprinkle of fresh cilantro.\"]', '{\"Calories\":\"275\",\"Fat\":\"1g (3% of Calories)\",\"Saturated Fat\":\"0g (0% DV)\",\"Cholesterol\":\"0mg (0% DV)\",\"Sodium\":\"480mg (21% DV)\",\"Carbohydrates\":\"51g (74% of Calories)\",\"Dietary Fiber\":\"17g (61% DV)\",\"Total Sugars\":\"9g\",\"Protein\":\"16g (23% of Calories)\",\"Vitamin A\":\"25% DV\",\"Vitamin C\":\"80% DV\",\"Vitamin D\":\"0% DV\",\"Vitamin E\":\"4% DV\",\"Vitamin K\":\"10% DV\",\"Thiamin (B1)\":\"30% DV\",\"Riboflavin (B2)\":\"10% DV\",\"Niacin (B3)\":\"8% DV\",\"Pantothenic Acid (B5)\":\"6% DV\",\"Pyridoxine (B6)\":\"20% DV\",\"Biotin (B7)\":\"15% DV\",\"Cobalamin (B12)\":\"0% DV\",\"Calcium\":\"12% DV\",\"Copper\":\"40% DV\",\"Folate\":\"65% DV\",\"Iron\":\"25% DV\",\"Magnesium\":\"30% DV\",\"Phosphorus\":\"25% DV\",\"Potassium\":\"28% DV\",\"Selenium\":\"8% DV\",\"Zinc\":\"15% DV\"}', 'Total Time: Remember that the Instant Pot needs about 10-15 minutes to come to pressure before the 30-minute countdown begins, plus the 10+ minutes for pressure release. Plan for a total time of around an hour from start to finish.\r\nNo Soaked Beans? If you forget to soak your beans (it happens to the best of us, darling), you can cook them from dry. Just rinse them well and increase the pressure cooking time to 50-55 minutes.\r\nTopping Ideas: This chili is a fantastic base for all sorts of toppings! Try it with a dollop of vegan sour cream, sliced avocado, crushed tortilla chips, or a squeeze of fresh lime juice.\r\nSpice Level: This recipe has a mild to medium heat. Feel free to omit the jalapeño and cayenne for a very mild chili, or add an extra jalapeño (with seeds!) if you prefer things a bit more... stimulating.', 0.00, 0, 15, 35, '6 servings', 'uploads/recipes/68f8b90a18c77-black-bean-chili-instant-pot.png', 2);

